import (
	context "context"
	fern "github.com/allof-duplicate-properties/fern"
	fernclient "github.com/allof-duplicate-properties/fern/client"
)

client := fernclient.NewClient()
response, err := client.CreatePlantOrder(
	context.TODO(),
	&fern.CreatePlantOrderRequest{
		PlantId: "plantId",
		Body: &fern.PlantOrder{
			OrderId:   "orderId",
			Amount:    1.1,
			Currency:  "currency",
			PlantName: "plantName",
		},
	},
)
